// KI Web Search Tool — D-031
// Phase A: controller KI (KI_BASE_URL = http://knowledge-index.ai-stack:8100)
// Phase B: set KI_BASE_URL to enhanced-worker address before dispatching.
//
// Input: JSON string with { query, collection?, max_results? }
// Output: JSON string summarising ingestion result

const KI_BASE_URL = process.env.KI_BASE_URL || 'http://knowledge-index.ai-stack:8100';
const KI_API_KEY  = process.env.KI_API_KEY  || '';

const input      = JSON.parse($input);
const query      = input.query;
const collection = input.collection  || 'web_research';
const maxResults = input.max_results || 5;

const headers = { 'Content-Type': 'application/json' };
if (KI_API_KEY) headers['Authorization'] = `Bearer ${KI_API_KEY}`;

const resp = await fetch(`${KI_BASE_URL}/v1/search`, {
  method:  'POST',
  headers,
  body:    JSON.stringify({ query, max_results: maxResults, collection }),
});

// 501 = web search not enabled on this node (TAVILY_API_KEY absent)
if (resp.status === 501) {
  return JSON.stringify({
    status:  'unavailable',
    message: 'Web search not enabled on this node (TAVILY_API_KEY not set). ' +
             'Phase B: target an enhanced-worker with web_search capability.',
    query,
    collection,
  });
}

if (!resp.ok) {
  const body = await resp.text();
  throw new Error(`KI /v1/search failed — HTTP ${resp.status}: ${body}`);
}

const data = await resp.json();
return JSON.stringify({
  status:             'ok',
  query:              data.query,
  results_found:      data.results_found,
  documents_ingested: data.documents_ingested,
  collection:         data.collection,
  custody_pushed:     data.custody_pushed,
  message: `Ingested ${data.documents_ingested} of ${data.results_found} web results ` +
           `into collection '${data.collection}'.`,
});

// KI Knowledge Query Tool — D-031
// Calls POST /query on the Knowledge Index Service and formats results.
// Targets the same KI node as ki_web_search (KI_BASE_URL env).
//
// Input: JSON string with { query, collection?, top_k? }
// Output: formatted context string with ranked passages and sources

const KI_BASE_URL = process.env.KI_BASE_URL || 'http://knowledge-index.ai-stack:8100';
const KI_API_KEY  = process.env.KI_API_KEY  || '';

const input      = JSON.parse($input);
const query      = input.query;
const collection = input.collection || 'web_research';
const topK       = input.top_k     || 5;

const headers = { 'Content-Type': 'application/json' };
if (KI_API_KEY) headers['Authorization'] = `Bearer ${KI_API_KEY}`;

const resp = await fetch(`${KI_BASE_URL}/query`, {
  method:  'POST',
  headers,
  body:    JSON.stringify({ query, collection, top_k: topK }),
});

if (!resp.ok) {
  const body = await resp.text();
  throw new Error(`KI /query failed — HTTP ${resp.status}: ${body}`);
}

const data    = await resp.json();
const results = data.results || [];

if (results.length === 0) {
  return 'No relevant information found in the knowledge base. ' +
         'Try calling ki_web_search first to ingest current information.';
}

const lines = results.map((r, i) => {
  const source = r.source || r.metadata?.url || 'unknown';
  const score  = typeof r.score === 'number' ? r.score.toFixed(3) : 'n/a';
  return `[${i + 1}] (relevance: ${score})\n${r.text}\nSource: ${source}`;
});

return `Retrieved ${results.length} passages from collection '${collection}':\n\n` +
       lines.join('\n\n---\n\n');
